function limparMensagem(texto) {
  if (typeof texto !== 'string') {
    return '';
  }

  function removerMetadataTecnico(str) {
    return str
      .replace(/"response_metadata"\s*:\s*{[^}]*}/g, '')
      .replace(/"additional_kwargs"\s*:\s*{[^}]*}/g, '')
      .replace(/"tool_calls"\s*:\s*\[\s*\]/g, '')
      .replace(/"invalid_tool_calls"\s*:\s*\[\s*\]/g, '')
      .replace(/"type"\s*:\s*"(ai|human)"/g, '')
      .replace(/"data"\s*:\s*{[^}]*}/g, '')
      .replace(/,\s*{[^}]*}/g, '')
      .replace(/,\s*\[\s*\]/g, '')
      .replace(/\s*:\s*null/g, '')
      .replace(/\s*:\s*\[\]/g, '')
      .replace(/\s*:\s*{}/g, '')
      .replace(/\s+/g, ' ')
      .replace(/^\s+|\s+$/g, '');
  }

  function limparCaracteresEspeciais(str) {
    return str
      .replace(/\\\\[rnt]/g, ' ')
      .replace(/\\\\\"/g, '')
      .replace(/\\\\\\\\/g, '')
      .replace(/[\x00-\x1F\x7F-\x9F]/g, '')
      .replace(/\"+/g, '')
      .replace(/[{}[\]]/g, '')
      .trim();
  }

  function extrairMensagemPrincipal(str) {
    const frases = str.split(/(?<=[.!?])\s+/);
    return frases
      .map(frase => frase.trim())
      .filter(frase => {
        return frase.length > 0 &&
          !frase.includes('tool_calls') &&
          !frase.includes('invalid_tool_calls') &&
          !frase.match(/^[:\s\[\]{}]+$/);
      })
      .join(' ');
  }

  let resultado = texto;
  resultado = removerMetadataTecnico(resultado);
  resultado = extrairMensagemPrincipal(resultado);
  resultado = limparCaracteresEspeciais(resultado);
  resultado = resultado
    .replace(/\s+/g, ' ')
    .replace(/^[\",\s]+|[\",\s]+$/g, '')
    .trim();
  return resultado;
}

function processarMensagens(items) {
  return items.map(item => {
    try {
      if (!item?.json?.mensagem) {
        return item;
      }
      let mensagem = item.json.mensagem;
      if (typeof mensagem === 'object') {
        try {
          mensagem = JSON.stringify(mensagem);
        } catch (e) {
          return item;
        }
      }
      const mensagemLimpa = limparMensagem(mensagem);
      if (mensagemLimpa && mensagemLimpa.length > 0) {
        item.json.mensagem = mensagemLimpa;
      }
      return { json: item.json };
    } catch (error) {
      return item;
    }
  });
}

try {
  const items = $input.all();
  return processarMensagens(items);
} catch (error) {
  throw error;
}

const item = $input.first();

if (!item || !item.json || !item.json.output) {
  throw new Error("A chave 'output' não foi encontrada no JSON de entrada.");
}

const textoEntrada = item.json.output;

let textoProcessado = textoEntrada.replace(/\n/g, " ");

// Substituições fonéticas para TTS pt-BR
textoProcessado = textoProcessado
  .replace(/\bn8n\b/gi, 'nêitiên')
  .replace(/\bMCP\b/g, 'ême cê pê')
  .replace(/\bRAG\b/g, 'réguê')
  .replace(/\bLLM\b/g, 'éle éle ême')
  .replace(/\bAPI\b/g, 'a pê i')
  .replace(/\bTTS\b/g, 'tê tê ésse')
  .replace(/\bIA\b/g, 'inteligência artificial')
  .replace(/https?:\/\/\S+/g, '')
  .replace(/#\w+/g, '');

// Remove emojis
textoProcessado = textoProcessado.replace(
  /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F700}-\u{1F77F}]|[\u{1F780}-\u{1F7FF}]|[\u{1F800}-\u{1F8FF}]|[\u{1F900}-\u{1F9FF}]|[\u{1FA00}-\u{1FA6F}]|[\u{1FA70}-\u{1FAFF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{FE00}-\u{FE0F}]|[\u{1F1E0}-\u{1F1FF}]/gu,
  ""
);

// Remove caracteres especiais mantendo pontuação útil para TTS
textoProcessado = textoProcessado.replace(/[^a-zA-Z0-9À-ÿ\s.,!?;:\-()]/g, "");

// Normaliza espaços
textoProcessado = textoProcessado.replace(/\s+/g, " ").trim();

return {
  textoOriginal: textoEntrada,
  textoSemQuebrasNemEmojisNemEspeciais: textoProcessado,
};

const textoOriginal = ($json.output ?? '').toString();

function sanitizarWhatsApp(texto) {
  return texto
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/\*(.*?)\*/g, '$1')
    .replace(/__(.*?)__/g, '$1')
    .replace(/_(.*?)_/g, '$1')
    .replace(/```[\s\S]*?```/g, '')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/^#{1,6}\s*/gm, '')
    .replace(/^\s*[-*]\s+/gm, '• ')
    .replace(/[^\p{L}\p{N}\s.,!?():\-•]/gu, '')
    .replace(/\s+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const textoLimpo = sanitizarWhatsApp(textoOriginal);

return [
  {
    json: {
      ...$json,
      output: textoLimpo
    }
  }
];
